Measuring Web Vitals in JavaScript

• Using the web-vitals library: Google’s official web-vitals npm package is the easiest and most accurate way to collect all metrics in production. It matches exactly what Chrome reports to the CrUX dataset.
// measure-vitals.js// npm install web-vitals
import { onLCP, onINP, onCLS, onFCP, onTTFB, onFID } from 'web-vitals';
// ── Send to your analytics endpoint ──────────────────
function sendToAnalytics(metric) {
const { name, value, rating, delta, id, navigationType } = metric;
// rating: 'good' | 'needs-improvement' | 'poor'
console.log(`[${name}] ${value.toFixed(2)} - ${rating}`);
// Send to Google Analytics 4
gtag('event', name, {
event_category: 'Web Vitals',
event_label: id, // unique per page load
value: Math.round(name === 'CLS' ? value * 1000 : value),
non_interaction: true,
metric_rating: rating,
metric_delta: delta, // change since last report
navigation_type: navigationType,
});
}
// ── Register all metric observers ────────────────────
onLCP(sendToAnalytics);
onINP(sendToAnalytics);
onCLS(sendToAnalytics);
onFCP(sendToAnalytics);
onTTFB(sendToAnalytics);
onFID(sendToAnalytics); // deprecated but still in some tools
2. Raw PerformanceObserver APIs:
// raw-observers.js// ── 1. Largest Contentful Paint ───────────────────────
let lcpValue = 0;
const lcpObserver = new PerformanceObserver((list) => {
const entries = list.getEntries();
const last = entries[entries.length - 1];
lcpValue = last.startTime;
console.log('LCP candidate:', lcpValue.toFixed(0), 'ms');
});
lcpObserver.observe({ type: 'largest-contentful-paint', buffered: true });
// Finalise LCP on user interaction or page hide
const finaliseLCP = () => {
lcpObserver.disconnect();
console.log('Final LCP:', lcpValue.toFixed(0), 'ms');
};
document.addEventListener('keydown', finaliseLCP, { once: true });
document.addEventListener('click', finaliseLCP, { once: true });
// ── 2. Cumulative Layout Shift ────────────────────────
let clsScore = 0, sessionValue = 0, sessionEntries = [], lastEntry;
new PerformanceObserver((list) => {
list.getEntries().forEach(entry => {
if (!entry.hadRecentInput) {
// Session window: max 5s duration, max 1s gap
if (lastEntry && (entry.startTime - lastEntry.startTime < 1000)
&& (entry.startTime - sessionEntries[0].startTime < 5000)) {
sessionValue += entry.value;
sessionEntries.push(entry);
} else {
sessionValue = entry.value;
sessionEntries = [entry];
}
if (sessionValue > clsScore) clsScore = sessionValue;
lastEntry = entry;
}
});
console.log('CLS:', clsScore.toFixed(4));
}).observe({ type: 'layout-shift', buffered: true });
// ── 3. Interaction to Next Paint ──────────────────────
let maxINP = 0;
new PerformanceObserver((list) => {
list.getEntries().forEach(entry => {
// INP = processingStart − startTime + (nextPaintTime − processingEnd)
const duration = entry.duration;
if (duration > maxINP) {
maxINP = duration;
console.log('New INP candidate:', maxINP.toFixed(0), 'ms',
'- target:', entry.target);
}
});
}).observe({ type: 'event', durationThreshold: 16, buffered: true });
// ── 4. Time to First Byte ─────────────────────────────
const nav = performance.getEntriesByType('navigation')[0];
const ttfb = nav.responseStart - nav.requestStart;
console.log('TTFB:', ttfb.toFixed(0), 'ms');
// ── 5. First Contentful Paint ─────────────────────────
new PerformanceObserver((list) => {
list.getEntries().forEach(entry => {
if (entry.name === 'first-contentful-paint') {
console.log('FCP:', entry.startTime.toFixed(0), 'ms');
}
});
}).observe({ type: 'paint', buffered: true });
// ── 6. Long Tasks (TBT building blocks) ───────────────
let tbt = 0;
new PerformanceObserver((list) => {
list.getEntries().forEach(entry => {
tbt += entry.duration - 50; // blocking time = duration beyond 50ms
console.log('Long task:', entry.duration.toFixed(0), 'ms | TBT so far:', tbt.toFixed(0));
});
}).observe({ type: 'longtask', buffered: true });
3. Real-World Dashboard Reporter
// vitals-reporter.js// Batched beacon reporter — sends all metrics on page hide
import { onLCP, onINP, onCLS, onFCP, onTTFB } from 'web-vitals';
const metrics = {};
function collect(metric) {
metrics[metric.name] = {
value: metric.value,
rating: metric.rating,
delta: metric.delta,
};
}
onLCP(collect); onINP(collect);
onCLS(collect); onFCP(collect); onTTFB(collect);
// Send all metrics at once when user leaves the page
document.addEventListener('visibilitychange', () => {
if (document.visibilityState === 'hidden') {
navigator.sendBeacon('/analytics/vitals', JSON.stringify({
url: location.href,
timestamp: Date.now(),
metrics,
connection: navigator?.connection?.effectiveType,
deviceMemory: navigator?.deviceMemory,
}));
}
});
Applications Across Industries

• E-commerce: LCP directly affects add-to-cart rates. Every 100ms of LCP delay can cost conversions at scale.

• News & Media: CLS improvements prevent accidental ad clicks and layout jumps that frustrate readers.

• SaaS / Web Apps: INP is critical — dashboards, editors, and data tools must respond to interactions instantly.

• Travel & Booking: TTFB improvements from CDN and server-side caching directly cut time-to-quote-visible.

• Mobile-First Markets: TBT reduction is essential on low-powered Android devices, where JS execution is 3–5× slower than on desktop.

• SEO-driven traffic: Passing the Core Web Vitals “Good” threshold gives a ranking signal boost across all queries.
Tools, Libraries & Workflows
Web Vitals are measured in two fundamentally different contexts — Lab (controlled, simulated, reproducible) and Field (real users, real devices, real networks). Both are essential.
ℹ️ Lab vs Field: Lab tools (Lighthouse, WebPageTest) run on a controlled machine with a throttled connection, fast to iterate but not representative. Field tools (CrUX, web-vitals.js) measure actual user sessions, accurate but slower to collect. Google’s ranking uses field data (75th percentile from CrUX).
Lab Tools

• 🔦 Lighthouse: Built into Chrome DevTools and available as a CLI/Node module. Measures LCP, CLS, TBT, FCP, SI, TTFB. Generates a 0–100 performance score. The gold standard for lab audits.

• 🚀 PageSpeed Insights: Google’s free web interface. Shows both Lab (Lighthouse) AND Field (CrUX) data side-by-side for any URL. The easiest way to check your real-world score.

• 🌐 WebPageTest: Test from real browsers worldwide, with filmstrip view, waterfall charts, and video comparison. Best for diagnosing TTFB and render-blocking resources at real geographic locations.

• 🛠 Chrome DevTools: Performance panel shows long tasks, layout shifts (red bars), and LCP candidates with overlays. The Elements panel highlights CLS-causing elements. Essential for debugging INP.
Field Tools (Real User Monitoring)

• 📊 CrUX Dashboard (Looker Studio): Google’s Chrome User Experience Report dataset. Shows 28-day rolling field data for any URL or origin. Free. The same data is used in Google Search rankings.

• 🔎 Core Web Vitals Report: Groups your pages into Good / Needs Improvement / Poor clusters based on CrUX data. Best for prioritising which page templates to fix first.

• 📦 web-vitals.js: Google’s official library. Tiny (<2.5kB gzip), accurate, matches CrUX methodology exactly. Integrates with any analytics backend. The right choice for custom RUM.

• ⚡ Datadog / Sentry / Vercel Speed: Full Real User Monitoring platforms with per-route breakdowns, session replay, and alerting. Best for engineering teams who need production observability at scale.
